userDefinedLinkHintCss:
div > .vimiumHintMarker {
  background: rgba(17, 19, 26, 0.72);
  border: 1px solid rgba(122, 162, 247, 0.75);
  border-radius: 0;
  box-shadow: none;
  color: #c0caf5;
  font-family: "JetBrains Mono", "FiraCode Nerd Font", monospace;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.04em;
  line-height: 1;
  padding: 2px 5px;
  text-shadow: none;
  text-transform: uppercase;
}

div > .vimiumHintMarker span {
  color: inherit;
  font-size: inherit;
  font-weight: inherit;
  line-height: inherit;
  text-shadow: none;
}

div > .vimiumHintMarker > .matchingCharacter {
  background: rgba(122, 162, 247, 0.9);
  border-radius: 0;
  box-shadow: none;
  color: #11131a;
  font-size: inherit;
  font-weight: inherit;
  line-height: inherit;
  padding: 0;
  text-shadow: none;
}
